namespace sv_7153ff32689c4fa1b914e15b74bab634.Services;

public class ApplicationState
{
    // Step 1: Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2: Experience
    public List<JobHistoryEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = [];

    // Track which steps have been completed
    public HashSet<int> CompletedSteps { get; } = [];

    public void MarkStepCompleted(int step) => CompletedSteps.Add(step);

    public bool IsStepCompleted(int step) => CompletedSteps.Contains(step);
}

public class JobHistoryEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Duration { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

@inherits LayoutComponentBase
@inject NavigationManager Nav

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <nav class="wizard-progress">
                <span class="wizard-step-label">Step @CurrentStep of 4</span>
                <div class="wizard-steps">
                    @for (int i = 1; i <= 4; i++)
                    {
                        var step = i;
                        <a href="@GetStepUrl(step)"
                           class="wizard-step @(step == CurrentStep ? "active" : "") @(step < CurrentStep ? "completed" : "")">
                            <span class="step-number">@step</span>
                            <span class="step-name">@GetStepName(step)</span>
                        </a>
                    }
                </div>
            </nav>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private int CurrentStep => GetCurrentStepFromUrl();

    private int GetCurrentStepFromUrl()
    {
        var path = new Uri(Nav.Uri).AbsolutePath;
        return path switch
        {
            "/apply/personal-info" => 1,
            "/apply/experience" => 2,
            "/apply/references" => 3,
            "/apply/review" => 4,
            _ => 1
        };
    }

    private static string GetStepUrl(int step) => step switch
    {
        1 => "/apply/personal-info",
        2 => "/apply/experience",
        3 => "/apply/references",
        4 => "/apply/review",
        _ => "/apply/personal-info"
    };

    private static string GetStepName(int step) => step switch
    {
        1 => "Personal Info",
        2 => "Experience",
        3 => "References",
        4 => "Review",
        _ => ""
    };
}

.wizard-progress {
    display: flex;
    align-items: center;
    gap: 1rem;
    width: 100%;
}

.wizard-step-label {
    font-weight: 600;
    white-space: nowrap;
}

.wizard-steps {
    display: flex;
    gap: 0.5rem;
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 0.25rem;
    padding: 0.25rem 0.75rem;
    border-radius: 1rem;
    text-decoration: none;
    font-size: 0.85rem;
    color: #6c757d;
    background: #e9ecef;
    transition: all 0.2s;
}

.wizard-step:hover {
    background: #dee2e6;
    color: #495057;
}

.wizard-step.active {
    background: #0d6efd;
    color: white;
    font-weight: 600;
}

.wizard-step.completed {
    background: #198754;
    color: white;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.25rem;
    height: 1.25rem;
    border-radius: 50%;
    background: rgba(255,255,255,0.3);
    font-size: 0.75rem;
    font-weight: 700;
}

.step-name {
    display: none;
}

@media (min-width: 768px) {
    .step-name {
        display: inline;
    }
}

