@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@inject NavigationManager Nav
@inject ApplicationState AppState

<PageTitle>Apply - Personal Info</PageTitle>

<h3>Personal Information</h3>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="AppState.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input type="email" class="form-control" @bind="AppState.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void Next()
    {
        AppState.MarkStepCompleted(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@inject NavigationManager Nav
@inject ApplicationState AppState

<PageTitle>Apply - Experience</PageTitle>

<h3>Work Experience</h3>

@foreach (var job in AppState.JobHistory)
{
    <div class="card mb-2 p-3">
        <div class="d-flex justify-content-between align-items-start">
            <div>
                <strong>@job.Title</strong> at @job.Company
                <br /><small class="text-muted">@job.Duration</small>
            </div>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(job)">✕</button>
        </div>
    </div>
}

<div class="card p-3 mb-3">
    <h6>Add Position</h6>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Company" @bind="newCompany" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Job Title" @bind="newTitle" />
        </div>
        <div class="col-md-3">
            <input class="form-control" placeholder="Duration" @bind="newDuration" />
        </div>
        <div class="col-md-1">
            <button class="btn btn-success" @onclick="AddJob">+</button>
        </div>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string newCompany = "";
    private string newTitle = "";
    private string newDuration = "";

    private void AddJob()
    {
        if (!string.IsNullOrWhiteSpace(newCompany) && !string.IsNullOrWhiteSpace(newTitle))
        {
            AppState.JobHistory.Add(new JobHistoryEntry
            {
                Company = newCompany,
                Title = newTitle,
                Duration = newDuration
            });
            newCompany = "";
            newTitle = "";
            newDuration = "";
        }
    }

    private void RemoveJob(JobHistoryEntry job) => AppState.JobHistory.Remove(job);

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        AppState.MarkStepCompleted(2);
        Nav.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@layout WizardLayout
@inject NavigationManager Nav
@inject ApplicationState AppState

<PageTitle>Apply - References</PageTitle>

<h3>References</h3>

@foreach (var reference in AppState.References)
{
    <div class="card mb-2 p-3">
        <div class="d-flex justify-content-between align-items-start">
            <div>
                <strong>@reference.Name</strong> — @reference.Relationship
                <br /><small class="text-muted">@reference.Email</small>
            </div>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveRef(reference)">✕</button>
        </div>
    </div>
}

<div class="card p-3 mb-3">
    <h6>Add Reference</h6>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Name" @bind="newName" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Email" @bind="newEmail" />
        </div>
        <div class="col-md-3">
            <input class="form-control" placeholder="Relationship" @bind="newRelationship" />
        </div>
        <div class="col-md-1">
            <button class="btn btn-success" @onclick="AddRef">+</button>
        </div>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string newName = "";
    private string newEmail = "";
    private string newRelationship = "";

    private void AddRef()
    {
        if (!string.IsNullOrWhiteSpace(newName) && !string.IsNullOrWhiteSpace(newEmail))
        {
            AppState.References.Add(new ReferenceContact
            {
                Name = newName,
                Email = newEmail,
                Relationship = newRelationship
            });
            newName = "";
            newEmail = "";
            newRelationship = "";
        }
    }

    private void RemoveRef(ReferenceContact r) => AppState.References.Remove(r);

    private void Back() => Nav.NavigateTo("/apply/experience");

    private void Next()
    {
        AppState.MarkStepCompleted(3);
        Nav.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout
@inject NavigationManager Nav
@inject ApplicationState AppState

<PageTitle>Apply - Review</PageTitle>

<h3>Review Your Application</h3>

<div class="card mb-3 p-3">
    <h5>Personal Information</h5>
    <dl class="row mb-0">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@AppState.Name</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@AppState.Email</dd>
    </dl>
</div>

<div class="card mb-3 p-3">
    <h5>Work Experience</h5>
    @if (AppState.JobHistory.Count == 0)
    {
        <p class="text-muted">No experience entries added.</p>
    }
    else
    {
        <ul class="list-group list-group-flush">
            @foreach (var job in AppState.JobHistory)
            {
                <li class="list-group-item">
                    <strong>@job.Title</strong> at @job.Company
                    <span class="text-muted">(@job.Duration)</span>
                </li>
            }
        </ul>
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @if (AppState.References.Count == 0)
    {
        <p class="text-muted">No references added.</p>
    }
    else
    {
        <ul class="list-group list-group-flush">
            @foreach (var r in AppState.References)
            {
                <li class="list-group-item">
                    <strong>@r.Name</strong> — @r.Relationship
                    <br /><small>@r.Email</small>
                </li>
            }
        </ul>
    }
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

